import React from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import './styles/global.css';

import LoginPage from './pages/LoginPage';
import RequestsPage from './pages/RequestsPage';
import RequestFormPage from './pages/RequestFormPage';
import RequestDetailPage from './pages/RequestDetailPage';
import DashboardPage from './pages/DashboardPage';
import PerformanceDashboardPage from './pages/PerformanceDashboardPage';
import ManagementDashboardPage from './pages/ManagementDashboardPage';
import AdminPage from './pages/AdminPage';
import NotificationsPage from './pages/NotificationsPage';
import PlanningBoardPage from './pages/PlanningBoardPage';
import ArchivePage from './pages/ArchivePage';
import ReportsPage from './pages/ReportsPage';
import StockPage from './pages/StockPage';
import OnboardingPage from './pages/OnboardingPage';

const ProtectedRoute = ({ children, roles }) => {
  const { user, loading } = useAuth();
  if (loading) return (
    <div style={{ minHeight: '100vh', display: 'flex', alignItems: 'center', justifyContent: 'center', background: 'var(--bg-primary)' }}>
      <span className="spinner" style={{ width: 36, height: 36 }}/>
    </div>
  );
  if (!user) return <Navigate to="/login" replace/>;
  if (roles && !roles.includes(user.role)) return <Navigate to="/requests" replace/>;
  return children;
};

function AppRoutes() {
  const { user } = useAuth();
  return (
    <Routes>
      <Route path="/login" element={
        user ? <Navigate to={user.role === 'requester' ? '/requests' : '/dashboard'} replace/> : <LoginPage/>
      }/>

      {/* Dashboards */}
      <Route path="/dashboard" element={
        <ProtectedRoute roles={['coordinator','manager','administrator','technician']}>
          <DashboardPage/>
        </ProtectedRoute>
      }/>
      <Route path="/dashboard/performance" element={
        <ProtectedRoute roles={['coordinator','manager','administrator']}>
          <PerformanceDashboardPage/>
        </ProtectedRoute>
      }/>
      <Route path="/dashboard/management" element={
        <ProtectedRoute roles={['manager','administrator']}>
          <ManagementDashboardPage/>
        </ProtectedRoute>
      }/>

      {/* Requests */}
      <Route path="/requests"     element={<ProtectedRoute><RequestsPage/></ProtectedRoute>}/>
      <Route path="/requests/new" element={
        <ProtectedRoute roles={['requester','coordinator','administrator']}>
          <RequestFormPage/>
        </ProtectedRoute>
      }/>
      <Route path="/requests/:id"      element={<ProtectedRoute><RequestDetailPage/></ProtectedRoute>}/>
      <Route path="/requests/:id/edit" element={<ProtectedRoute><RequestFormPage/></ProtectedRoute>}/>

      {/* Planning */}
      <Route path="/planning" element={
        <ProtectedRoute roles={['coordinator','manager','administrator','technician']}>
          <PlanningBoardPage/>
        </ProtectedRoute>
      }/>

      {/* Archive */}
      <Route path="/archive" element={
        <ProtectedRoute roles={['coordinator','manager','administrator']}>
          <ArchivePage/>
        </ProtectedRoute>
      }/>

      {/* Reports */}
      <Route path="/reports" element={
        <ProtectedRoute roles={['coordinator','manager','administrator']}>
          <ReportsPage/>
        </ProtectedRoute>
      }/>

      {/* Notifications */}
      <Route path="/notifications" element={<ProtectedRoute><NotificationsPage/></ProtectedRoute>}/>

      {/* Admin */}
      <Route path="/stock" element={
        <ProtectedRoute roles={['coordinator','manager','administrator']}>
          <StockPage/>
        </ProtectedRoute>
      }/>

      <Route path="/onboarding" element={
        <ProtectedRoute>
          <OnboardingPage/>
        </ProtectedRoute>
      }/>

      <Route path="/admin" element={
        <ProtectedRoute roles={['administrator']}>
          <AdminPage/>
        </ProtectedRoute>
      }/>

      {/* Root redirect */}
      <Route path="/" element={
        <ProtectedRoute>
          {user?.role === 'requester'
            ? <Navigate to="/requests" replace/>
            : <Navigate to="/dashboard" replace/>
          }
        </ProtectedRoute>
      }/>
      <Route path="*" element={<Navigate to="/" replace/>}/>
    </Routes>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter>
        <AppRoutes/>
      </BrowserRouter>
    </AuthProvider>
  );
}
